import MessagesDropdown from '@/components/MessagesDropdown';
import NotificationsDropdown from '@/components/NotificationsDropdown';
import ProfileCompletionBanner from '@/components/ProfileCompletionBanner';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { useCart } from '@/contexts/CartContext';
import { NotificationsProvider } from '@/contexts/NotificationsContext';
import { type SharedData } from '@/types';
import { Link, router, usePage } from '@inertiajs/react';
import { Briefcase, ChevronDown, Contact, Heart, House, LogOut, Menu, Package, PenTool, Phone, ShoppingCart, Store, User, X } from 'lucide-react';
import React, { useEffect, useRef, useState } from 'react';

interface BuyerLayoutProps {
    children: React.ReactNode;
    title?: string;
}

function BuyerLayoutContent({ children, title }: BuyerLayoutProps) {
    const [isMenuOpen, setIsMenuOpen] = useState(false);
    const [isUserMenuOpen, setIsUserMenuOpen] = useState(false);
    const userMenuRef = useRef<HTMLDivElement>(null);
    const mobileMenuRef = useRef<HTMLDivElement>(null);
    const mobileMenuButtonRef = useRef<HTMLButtonElement>(null);

    const { totalItems } = useCart();
    const { auth, profileCompletion, wishlistCount } = usePage<
        SharedData & {
            profileCompletion?: {
                status: {
                    is_complete: boolean;
                    percentage: number;
                    completed_fields: number;
                    total_fields: number;
                    missing_fields: Array<{ field: string; label: string }>;
                    has_email_verified: boolean;
                    has_profile_picture: boolean;
                };
                recommendation: {
                    title: string;
                    description: string;
                    action: string;
                    url: string;
                    priority: 'critical' | 'high' | 'medium' | 'low';
                    missing_fields?: Array<{ field: string; label: string }>;
                } | null;
            };
        }
    >().props;
    const user = auth.user;
    const currentPath = usePage().url;

    const handleLogout = () => {
        router.post('/logout');
    };

    useEffect(() => {
        function handleClickOutside(event: MouseEvent) {
            if (userMenuRef.current && !userMenuRef.current.contains(event.target as Node)) {
                setIsUserMenuOpen(false);
            }
            if (
                mobileMenuRef.current &&
                !mobileMenuRef.current.contains(event.target as Node) &&
                mobileMenuButtonRef.current &&
                !mobileMenuButtonRef.current.contains(event.target as Node)
            ) {
                setIsMenuOpen(false);
            }
        }

        document.addEventListener('mousedown', handleClickOutside);
        return () => {
            document.removeEventListener('mousedown', handleClickOutside);
        };
    }, []);

    // Close menus when route changes
    useEffect(() => {
        setIsMenuOpen(false);
        setIsUserMenuOpen(false);
    }, [currentPath]);

    // Check if navigation item is active
    const isActiveRoute = (href: string) => {
        return currentPath.startsWith(href);
    };

    const buyerNavigation = [
        { name: 'Home', href: '/buyer/dashboard', icon: House },
        { name: 'Marketplace', href: '/buyer/products', icon: Store },
        { name: 'Artisans', href: '/buyer/sellers', icon: User },
        { name: 'My Orders', href: '/buyer/orders', icon: Package },
        { name: 'Custom Orders', href: '/buyer/custom-orders', icon: PenTool },
    ];

    return (
        <div className="min-h-screen overflow-x-hidden bg-white" style={{ colorScheme: 'light' }}>
            {/* Buyer Navigation Header */}
            <header className="fixed top-0 z-50 w-full border-b border-gray-200 bg-white shadow-sm">
                <nav className="mx-auto w-full max-w-7xl px-4 sm:px-6 lg:px-8" role="navigation" aria-label="Main navigation">
                    <div className="flex h-16 items-center justify-between">
                        {/* Logo */}
                        <div className="min-w-0 flex-shrink-0">
                            <Link
                                href="/buyer/dashboard"
                                className="flex items-center gap-2 rounded-xl px-2 py-2 transition-all duration-300 hover:scale-105 focus:ring-2 focus:ring-primary/50 focus:ring-offset-2 focus:outline-none active:scale-95"
                                aria-label="Support Local - Go to dashboard"
                            >
                                <div className="flex h-10 w-10 flex-shrink-0 items-center justify-center rounded-lg bg-gradient-to-br from-amber-500 to-orange-600 shadow-md">
                                    <svg className="h-6 w-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                        <path
                                            strokeLinecap="round"
                                            strokeLinejoin="round"
                                            strokeWidth="2"
                                            d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M9 5l8 4"
                                        />
                                    </svg>
                                </div>
                                <span className="hidden bg-gradient-to-r from-amber-600 to-orange-600 bg-clip-text text-xl font-bold text-transparent sm:inline">
                                    Support Local
                                </span>
                            </Link>
                        </div>

                        {/* Desktop Navigation - Buyer Specific */}
                        <div className="hidden flex-shrink-0 lg:block" style={{ colorScheme: 'light' }}>
                            <div className="flex items-center space-x-0.5">
                                {buyerNavigation.map((item) => {
                                    const Icon = item.icon;
                                    const isActive = isActiveRoute(item.href);
                                    return (
                                        <Link
                                            key={item.name}
                                            href={item.href}
                                            className={`group relative flex items-center gap-2 rounded-xl px-3 py-2 text-sm font-medium whitespace-nowrap transition-all duration-300 focus:ring-2 focus:ring-orange-500/50 focus:ring-offset-2 focus:outline-none ${isActive
                                                ? 'border border-orange-200 bg-gradient-to-r from-orange-100 to-amber-50 shadow-inner'
                                                : 'hover:bg-gray-50 hover:shadow-sm'
                                                }`}
                                            style={{ color: isActive ? '#c2410c' : '#374151' }}
                                            aria-current={isActive ? 'page' : undefined}
                                        >
                                            <Icon
                                                className="h-4 w-4 flex-shrink-0 transition-all duration-300"
                                                style={{ color: isActive ? '#ea580c' : '#6b7280' }}
                                            />
                                            <span className="relative">
                                                {item.name}
                                                {isActive && (
                                                    <span className="absolute right-0 -bottom-1 left-0 h-0.5 rounded-full bg-gradient-to-r from-orange-500 to-amber-400"></span>
                                                )}
                                            </span>
                                        </Link>
                                    );
                                })}
                            </div>
                        </div>

                        {/* Right side - User specific actions */}
                        <div className="flex flex-shrink-0 items-center space-x-1">
                            {/* Messages Dropdown */}
                            <MessagesDropdown currentUserId={user.id} />

                            {/* Notifications Dropdown */}
                            <NotificationsDropdown
                                userRole="buyer"
                                buttonClassName="group relative rounded-xl p-2 text-gray-600 transition-all duration-300 hover:bg-primary/5 hover:text-primary hover:shadow-sm focus:ring-2 focus:ring-primary/50 focus:ring-offset-2 focus:outline-none"
                            />

                            {/* Wishlist Icon */}
                            <Link
                                href="/wishlist"
                                className={`group relative flex-shrink-0 rounded-xl p-2 transition-all duration-300 focus:ring-2 focus:ring-orange-500/50 focus:ring-offset-2 focus:outline-none ${isActiveRoute('/wishlist')
                                    ? 'bg-orange-100 shadow-sm ring-1 ring-orange-200'
                                    : 'hover:bg-orange-50 hover:shadow-sm'
                                    }`}
                                style={{ colorScheme: 'light' }}
                                aria-label={`Wishlist ${(wishlistCount ?? 0) > 0 ? `(${wishlistCount} items)` : '(empty)'}`}
                            >
                                <Heart
                                    className="h-5 w-5 transition-transform duration-300 group-hover:scale-110"
                                    style={{ color: isActiveRoute('/wishlist') ? '#ea580c' : '#4b5563' }}
                                />
                                {(wishlistCount ?? 0) > 0 && (
                                    <span className="absolute -top-1 -right-1 flex h-5 w-5 items-center justify-center rounded-full bg-gradient-to-r from-pink-500 to-red-500 text-xs font-medium text-white shadow-sm">
                                        {wishlistCount! > 99 ? '99+' : wishlistCount}
                                    </span>
                                )}
                            </Link>

                            {/* Cart Icon */}
                            <Link
                                href="/buyer/cart"
                                className={`group relative flex-shrink-0 rounded-xl p-2 transition-all duration-300 focus:ring-2 focus:ring-orange-500/50 focus:ring-offset-2 focus:outline-none ${isActiveRoute('/buyer/cart')
                                    ? 'bg-orange-100 shadow-sm ring-1 ring-orange-200'
                                    : 'hover:bg-orange-50 hover:shadow-sm'
                                    }`}
                                style={{ colorScheme: 'light' }}
                                aria-label={`Shopping cart ${totalItems > 0 ? `(${totalItems} items)` : '(empty)'}`}
                            >
                                <ShoppingCart
                                    className="h-5 w-5 transition-transform duration-300 group-hover:scale-110"
                                    style={{ color: isActiveRoute('/buyer/cart') ? '#ea580c' : '#4b5563' }}
                                />
                                {totalItems > 0 && (
                                    <span className="absolute -top-1 -right-1 flex h-5 w-5 items-center justify-center rounded-full bg-gradient-to-r from-red-500 to-red-600 text-xs font-medium text-white shadow-sm">
                                        {totalItems > 99 ? '99+' : totalItems}
                                    </span>
                                )}
                            </Link>

                            {/* User Profile Section with Dropdown */}
                            <div className="relative hidden flex-shrink-0 md:block" ref={userMenuRef}>
                                <button
                                    onClick={() => setIsUserMenuOpen(!isUserMenuOpen)}
                                    className={`flex items-center space-x-2 rounded-xl p-2 transition-all duration-300 focus:ring-2 focus:ring-primary/50 focus:ring-offset-2 focus:outline-none ${isUserMenuOpen
                                        ? 'bg-gradient-to-r from-primary/10 to-primary/5 shadow-md ring-2 ring-primary/20'
                                        : 'hover:bg-gray-50 hover:shadow-sm'
                                        }`}
                                    aria-expanded={isUserMenuOpen}
                                    aria-haspopup="true"
                                    aria-label="User menu"
                                >
                                    <Avatar className="h-9 w-9 ring-2 ring-gray-100 transition-all duration-300 hover:ring-primary/30">
                                        <AvatarImage src={user?.avatar_url || user?.avatar || undefined} alt={user?.name || 'User'} />
                                        <AvatarFallback className="bg-gradient-to-br from-primary/20 to-primary/10 text-sm font-semibold text-primary">
                                            {user?.name
                                                ? user.name
                                                    .split(' ')
                                                    .map((n: string) => n[0])
                                                    .join('')
                                                    .toUpperCase()
                                                    .slice(0, 2)
                                                : 'U'}
                                        </AvatarFallback>
                                    </Avatar>
                                    <div className="hidden text-left sm:block">
                                        <p className="text-sm font-semibold text-gray-900">{user?.name}</p>
                                        <p className="text-xs font-medium text-gray-500">Buyer Account</p>
                                    </div>
                                    <ChevronDown
                                        className={`h-4 w-4 text-gray-400 transition-all duration-300 ${isUserMenuOpen ? 'rotate-180 text-primary' : 'group-hover:text-primary'
                                            }`}
                                    />
                                </button>

                                {/* Dropdown Menu */}
                                {isUserMenuOpen && (
                                    <div
                                        className="absolute top-full right-0 z-50 mt-3 w-64 rounded-xl border border-gray-200 bg-white py-2 shadow-xl ring-1 ring-black/5"
                                        role="menu"
                                        aria-orientation="vertical"
                                    >
                                        {/* User Info Header */}
                                        <div className="border-b border-gray-100 px-4 py-3">
                                            <p className="text-sm font-semibold text-gray-900">{user?.name}</p>
                                            <p className="text-sm text-gray-600">{user?.email}</p>
                                            <span className="mt-2 inline-flex items-center rounded-full bg-gradient-to-r from-green-100 to-emerald-100 px-3 py-1 text-xs font-semibold text-green-800 ring-1 ring-green-200">
                                                ✓ Buyer Account
                                            </span>
                                        </div>

                                        {/* Menu Items */}
                                        <div className="py-2">
                                            <Link
                                                href="/buyer/profile"
                                                className="group mx-2 flex items-center rounded-lg px-4 py-3 text-sm font-medium text-gray-700 transition-all duration-300 hover:bg-primary/5 hover:text-primary focus:bg-primary/5 focus:text-primary focus:outline-none"
                                                onClick={() => setIsUserMenuOpen(false)}
                                                role="menuitem"
                                            >
                                                <User className="mr-3 h-4 w-4 text-gray-400 transition-colors duration-300 group-hover:text-primary" />
                                                Profile & Settings
                                            </Link>

                                            <div className="mx-4 my-2 border-t border-gray-100"></div>

                                            <Link
                                                href="/seller/apply"
                                                className="group mx-2 flex items-center rounded-lg px-4 py-3 text-sm font-medium text-gray-700 transition-all duration-300 hover:bg-gradient-to-r hover:from-orange-50 hover:to-amber-50 hover:text-orange-700 focus:bg-orange-50 focus:text-orange-700 focus:outline-none"
                                                onClick={() => setIsUserMenuOpen(false)}
                                                role="menuitem"
                                            >
                                                <Briefcase className="mr-3 h-4 w-4 text-gray-400 transition-colors duration-300 group-hover:text-orange-600" />
                                                <div>
                                                    <span>Become a Seller</span>
                                                    <p className="text-xs text-gray-500 group-hover:text-orange-600">Start selling your products</p>
                                                </div>
                                            </Link>

                                            <div className="mx-4 my-2 border-t border-gray-100"></div>

                                            <button
                                                onClick={() => {
                                                    setIsUserMenuOpen(false);
                                                    handleLogout();
                                                }}
                                                className="group mx-2 flex w-full items-center rounded-lg px-4 py-3 text-sm font-medium text-red-600 transition-all duration-300 hover:bg-gradient-to-r hover:from-red-50 hover:to-red-50 hover:text-red-700 focus:bg-red-50 focus:text-red-700 focus:outline-none"
                                                role="menuitem"
                                            >
                                                <LogOut className="mr-3 h-4 w-4 transition-colors duration-300" />
                                                Sign Out
                                            </button>
                                        </div>
                                    </div>
                                )}
                            </div>

                            {/* Mobile menu button */}
                            <div className="ml-1 flex-shrink-0 lg:hidden">
                                <button
                                    ref={mobileMenuButtonRef}
                                    onClick={() => setIsMenuOpen(!isMenuOpen)}
                                    className="rounded-xl p-2 text-gray-600 transition-all duration-300 hover:bg-primary/5 hover:text-primary focus:ring-2 focus:ring-primary/50 focus:ring-offset-2 focus:outline-none"
                                    aria-expanded={isMenuOpen}
                                    aria-label="Toggle navigation menu"
                                >
                                    <div className="relative h-6 w-6">
                                        <Menu
                                            className={`pointer-events-none absolute inset-0 h-6 w-6 transition-all duration-300 ${isMenuOpen ? 'rotate-180 opacity-0' : 'rotate-0 opacity-100'}`}
                                        />
                                        <X
                                            className={`pointer-events-none absolute inset-0 h-6 w-6 transition-all duration-300 ${isMenuOpen ? 'rotate-0 opacity-100' : '-rotate-180 opacity-0'}`}
                                        />
                                    </div>
                                </button>
                            </div>
                        </div>
                    </div>

                    {/* Mobile Navigation Menu */}
                    <div
                        className={`overflow-hidden transition-all duration-300 ease-in-out lg:hidden ${isMenuOpen ? 'max-h-screen opacity-100' : 'max-h-0 opacity-0'
                            }`}
                        ref={mobileMenuRef}
                    >
                        <div className="border-t border-gray-200 bg-white px-4 py-4 shadow-lg">
                            <div className="space-y-2">
                                {buyerNavigation.map((item) => {
                                    const Icon = item.icon;
                                    const isActive = isActiveRoute(item.href);
                                    return (
                                        <Link
                                            key={item.name}
                                            href={item.href}
                                            className={`flex items-center gap-4 rounded-xl px-4 py-3 text-base font-medium transition-all duration-300 ${isActive
                                                ? 'border border-orange-200 bg-gradient-to-r from-orange-100 to-amber-50 text-orange-700'
                                                : 'text-gray-700 hover:bg-gray-50 hover:text-orange-600'
                                                }`}
                                            onClick={() => {
                                                setIsMenuOpen(false);
                                                setIsUserMenuOpen(false);
                                            }}
                                        >
                                            <Icon className={`h-5 w-5 ${isActive ? 'text-orange-600' : 'text-gray-500'}`} />
                                            <span>{item.name}</span>
                                            {isActive && <div className="ml-auto h-2 w-2 rounded-full bg-orange-500"></div>}
                                        </Link>
                                    );
                                })}
                            </div>

                            {/* Mobile User Info & Actions */}
                            <div className="mt-6 border-t border-gray-200 pt-4">
                                <div className="flex items-center gap-4 rounded-xl bg-gray-50 px-4 py-3">
                                    <Avatar className="h-10 w-10">
                                        <AvatarImage src={user?.avatar_url || user?.avatar || undefined} alt={user?.name || 'User'} />
                                        <AvatarFallback className="bg-primary/10 font-semibold text-primary">
                                            {user?.name
                                                ? user.name
                                                    .split(' ')
                                                    .map((n: string) => n[0])
                                                    .join('')
                                                    .toUpperCase()
                                                    .slice(0, 2)
                                                : 'U'}
                                        </AvatarFallback>
                                    </Avatar>
                                    <div className="flex-1">
                                        <p className="font-semibold text-gray-900">{user?.name}</p>
                                        <p className="text-sm text-gray-600">{user?.email}</p>
                                    </div>
                                </div>

                                <div className="mt-3 space-y-2">
                                    <Link
                                        href="/buyer/profile"
                                        className="flex items-center gap-3 rounded-xl px-4 py-3 text-gray-700 transition-all duration-300 hover:bg-primary/5 hover:text-primary"
                                        onClick={() => setIsMenuOpen(false)}
                                    >
                                        <User className="h-5 w-5" />
                                        Profile & Settings
                                    </Link>

                                    <button
                                        onClick={() => {
                                            setIsMenuOpen(false);
                                            handleLogout();
                                        }}
                                        className="flex w-full items-center gap-3 rounded-xl px-4 py-3 text-red-600 transition-all duration-300 hover:bg-red-50 hover:text-red-700"
                                    >
                                        <LogOut className="h-5 w-5" />
                                        Sign Out
                                    </button>
                                </div>
                            </div>
                        </div>
                    </div>
                </nav>
            </header>
            <div className="h-16"></div>

            {/* Page Title */}
            {title && (
                <div className="bg-slate-50 py-4 sm:py-6">
                    <div className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8">
                        <h1 className="text-xl font-bold text-slate-900 sm:text-2xl">{title}</h1>
                    </div>
                </div>
            )}

            {/* Profile Completion Banner */}
            {profileCompletion && profileCompletion.status && (!profileCompletion.status.is_complete || profileCompletion.recommendation) && (
                <div className="bg-slate-50">
                    <div className="mx-auto max-w-7xl px-4 py-4 sm:px-6 lg:px-8">
                        <ProfileCompletionBanner
                            status={profileCompletion.status}
                            recommendation={profileCompletion.recommendation}
                            dismissible={
                                // Non-dismissible on cart and checkout pages if profile is incomplete
                                profileCompletion.status.is_complete || (!currentPath.includes('/cart') && !currentPath.includes('/checkout'))
                            }
                        />
                    </div>
                </div>
            )}

            {/* Main Content */}
            <main className="flex-1 bg-white">{children}</main>

            {/* Footer - Buyer specific */}
            <footer className="bg-gradient-to-br from-gray-900 via-gray-800 to-gray-900 text-white">
                <div className="mx-auto max-w-7xl px-4 py-12 sm:px-6 sm:py-16 lg:px-8">
                    <div className="grid grid-cols-1 gap-8 sm:grid-cols-2 md:gap-12 lg:grid-cols-4">
                        {/* Brand Section */}
                        <div className="col-span-1 sm:col-span-2">
                            <div className="mb-4 flex items-center gap-2">
                                <div className="flex h-10 w-10 items-center justify-center rounded-lg bg-gradient-to-br from-amber-500 to-orange-600 shadow-lg">
                                    <svg className="h-6 w-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                        <path
                                            strokeLinecap="round"
                                            strokeLinejoin="round"
                                            strokeWidth="2"
                                            d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M9 5l8 4"
                                        />
                                    </svg>
                                </div>
                                <h3 className="bg-gradient-to-r from-amber-400 to-orange-400 bg-clip-text text-2xl font-bold text-transparent">
                                    Support Local
                                </h3>
                            </div>
                            <p className="mb-6 leading-relaxed text-gray-300">
                                Your trusted marketplace for authentic, handcrafted products from talented local artisans. Every purchase supports
                                creative communities.
                            </p>
                            <div className="flex flex-wrap gap-3 sm:gap-4">
                                <a
                                    href="#"
                                    className="flex h-10 w-10 items-center justify-center rounded-full bg-gray-800 text-gray-400 transition-all hover:scale-110 hover:bg-gradient-to-r hover:from-amber-600 hover:to-orange-600 hover:text-white"
                                >
                                    <svg className="h-5 w-5" fill="currentColor" viewBox="0 0 24 24">
                                        <path d="M24 12.073c0-6.627-5.373-12-12-12s-12 5.373-12 12c0 5.99 4.388 10.954 10.125 11.854v-8.385H7.078v-3.47h3.047V9.43c0-3.007 1.792-4.669 4.533-4.669 1.312 0 2.686.235 2.686.235v2.953H15.83c-1.491 0-1.956.925-1.956 1.874v2.25h3.328l-.532 3.47h-2.796v8.385C19.612 23.027 24 18.062 24 12.073z" />
                                    </svg>
                                </a>
                                <a
                                    href="#"
                                    className="flex h-10 w-10 items-center justify-center rounded-full bg-gray-800 text-gray-400 transition-all hover:scale-110 hover:bg-gradient-to-r hover:from-amber-600 hover:to-orange-600 hover:text-white"
                                >
                                    <svg className="h-5 w-5" fill="currentColor" viewBox="0 0 24 24">
                                        <path d="M12 2.163c3.204 0 3.584.012 4.85.07 3.252.148 4.771 1.691 4.919 4.919.058 1.265.069 1.645.069 4.849 0 3.205-.012 3.584-.069 4.849-.149 3.225-1.664 4.771-4.919 4.919-1.266.058-1.644.07-4.85.07-3.204 0-3.584-.012-4.849-.07-3.26-.149-4.771-1.699-4.919-4.92-.058-1.265-.07-1.644-.07-4.849 0-3.204.013-3.583.07-4.849.149-3.227 1.664-4.771 4.919-4.919 1.266-.057 1.645-.069 4.849-.069zm0-2.163c-3.259 0-3.667.014-4.947.072-4.358.2-6.78 2.618-6.98 6.98-.059 1.281-.073 1.689-.073 4.948 0 3.259.014 3.668.072 4.948.2 4.358 2.618 6.78 6.98 6.98 1.281.058 1.689.072 4.948.072 3.259 0 3.668-.014 4.948-.072 4.354-.2 6.782-2.618 6.979-6.98.059-1.28.073-1.689.073-4.948 0-3.259-.014-3.667-.072-4.947-.196-4.354-2.617-6.78-6.979-6.98-1.281-.059-1.69-.073-4.949-.073zm0 5.838c-3.403 0-6.162 2.759-6.162 6.162s2.759 6.163 6.162 6.163 6.162-2.759 6.162-6.163c0-3.403-2.759-6.162-6.162-6.162zm0 10.162c-2.209 0-4-1.79-4-4 0-2.209 1.791-4 4-4s4 1.791 4 4c0 2.21-1.791 4-4 4zm6.406-11.845c-.796 0-1.441.645-1.441 1.44s.645 1.44 1.441 1.44c.795 0 1.439-.645 1.439-1.44s-.644-1.44-1.439-1.44z" />
                                    </svg>
                                </a>
                                <a
                                    href="#"
                                    className="flex h-10 w-10 items-center justify-center rounded-full bg-gray-800 text-gray-400 transition-all hover:scale-110 hover:bg-gradient-to-r hover:from-amber-600 hover:to-orange-600 hover:text-white"
                                >
                                    <svg className="h-5 w-5" fill="currentColor" viewBox="0 0 24 24">
